"""
mkt-christ commentary — Psalms 90–95
Run: python3 scripts/zc-christ-psalms-90-95.py

Key NT connections:
  Ps90:4   → 2 Pet 3:8 (shadow — thousand years as one day, eschatology)
  Ps90:12  → 1 Cor 1:30 (shadow — wisdom from Christ)
  Ps91:11-12 → Matt 4:6; Luke 4:10-11 (direct — Satan quotes to Christ)
  Ps91:13  → Luke 10:19; Gen 3:15 (shadow — treading serpents)
  Ps93:1   → Rev 19:6; Matt 28:18 (direct — LORD reigns / Christ enthroned)
  Ps94:11  → 1 Cor 3:20 (direct — Paul cites: thoughts are futile)
  Ps95:7-8 → Heb 3:7-8 (direct — Holy Spirit quotes; today/harden hearts)
  Ps95:9-10 → Heb 3:9-10 (direct — wilderness testing / going astray)
  Ps95:11  → Heb 3:11; 4:9-11 (direct — my rest / sabbath rest in Christ)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"90": {"1": "<p><span class=\"level\">revelation of God</span> <em>Lord, you have been our dwelling place in all generations.</em> God as dwelling place — fulfilled in Christ who is Immanuel, God-with-us (Matt 1:23). John's Prologue declares the ultimate dwelling: <em>the Word became flesh and dwelt among us</em> (John 1:14). The dwelling place that sheltered every generation is now made flesh; in Christ, God becomes the home his people have always needed (John 14:2-3).</p>", "2": "<p><span class=\"level\">revelation of God</span> <em>Before the mountains were brought forth, or ever you had formed the earth and the world, from everlasting to everlasting you are God.</em> The eternal God — Christ's own claim: <em>before Abraham was, I am</em> (John 8:58). Hebrews opens with this eternity: <em>you, Lord, laid the foundation of the earth in the beginning, and the heavens are the work of your hands</em> (Heb 1:10). The everlasting God is the same Jesus Christ who is <em>the same yesterday and today and forever</em> (Heb 13:8).</p>", "3": "<p><span class=\"level\">shadow</span> <em>You return man to dust and say, Return, O children of man!</em> God returning man to dust — and Christ reversing the return. <em>To dust you shall return</em> (Gen 3:19) is the consequence Christ absorbs: he is laid in the earth (John 19:41-42) and returns from it in resurrection. His <em>Come forth!</em> to Lazarus (John 11:43) is the divine call that reverses the return to dust.</p>", "4": "<p><span class=\"level\">shadow</span> <em>For a thousand years in your sight are but as yesterday when it is past, or as a watch in the night.</em> Divine timelessness applied to eschatological expectation: <em>with the Lord one day is as a thousand years, and a thousand years as one day</em> (2 Pet 3:8). Peter uses this verse to explain why Christ's coming seems delayed — from God's perspective, no time has passed. The eternal Son inhabits this timelessness; the delay of the parousia is patience, not failure.</p>", "5": "<p><span class=\"level\">shadow</span> <em>You sweep them away as with a flood; they are like a dream, like grass that is renewed in the morning:</em> Human transience like grass — the Incarnation enters this transience. Christ becomes the mortal, grass-like human being (Isa 40:6-8 — <em>all flesh is grass</em>) and transforms it from within by resurrection. The flood that sweeps away is the very flood he walks through (baptism into death) and rises from.</p>", "6": "<p><span class=\"level\">shadow</span> <em>in the morning it flourishes and is renewed; in the evening it fades and withers.</em> The grass that flourishes and withers — the pattern of death and resurrection. Christ enters the evening of human existence (Good Friday) and becomes the one who flourishes in the morning of the resurrection (Easter Sunday — <em>early on the first day of the week</em>, John 20:1). His resurrection transforms the withering pattern.</p>", "7": "<p><span class=\"level\">shadow</span> <em>For we are brought to an end by your anger; by your wrath we are dismayed.</em> God's wrath bringing to an end — the judgment Christ absorbs. The wrath that dismays humanity falls on Christ at the cross: <em>Christ redeemed us from the curse of the law by becoming a curse for us</em> (Gal 3:13). He is brought to an end by the wrath that humanity deserved, so that those in him face no condemning wrath (Rom 8:1).</p>", "8": "<p><span class=\"level\">shadow</span> <em>You have set our iniquities before you, our secret sins in the light of your countenance.</em> Iniquities set before the divine face — the transparency that the cross reveals. God's omniscient knowledge of sin is the foundation of the atonement: <em>him who knew no sin he made to be sin on our behalf</em> (2 Cor 5:21). The secret sins set in God's light were set on Christ so they would not condemn those who believe.</p>", "9": "<p><span class=\"level\">shadow</span> <em>For all our days pass away under your wrath; we bring our years to an end like a sigh.</em> Days passing under wrath — the universal human condition that Christ entered. He lived under the weight of human mortality and the divine wrath that attended it, <em>made under the law to redeem those who were under the law</em> (Gal 4:4-5). His sighing on the cross (Mark 15:37) is the last sigh of the old order ending.</p>", "10": "<p><span class=\"level\">shadow</span> <em>The years of our life are seventy, or even by reason of strength eighty; yet their span is but toil and trouble; they are soon gone, and we fly away.</em> The brevity of life — your life is a vapor (James 4:14). Christ entered the brevity of human life (born, living approximately 33 years, dying) and transformed it. <em>I am the resurrection and the life</em> (John 11:25) — he who is eternal life takes on the 70-year span so that those in him receive eternal years.</p>", "11": "<p><span class=\"level\">shadow</span> <em>Who considers the power of your anger, and your wrath according to the fear of you?</em> The power of divine anger — which only Christ fully considered and bore. He who feared God perfectly (Heb 5:7 — <em>heard because of his reverence</em>) also bore the full weight of divine wrath at the cross. No human fully considers this power; the Son of God alone meets it and absorbs it in his own body.</p>", "12": "<p><span class=\"level\">shadow</span> <em>So teach us to number our days that we may get a heart of wisdom.</em> A heart of wisdom — found in Christ: <em>Christ Jesus, who became to us wisdom from God</em> (1 Cor 1:30). To number one's days is the posture Christ models: <em>I must work the works of him who sent me while it is day; night is coming when no one can work</em> (John 9:4). The urgency of numbered days becomes the church's mission-posture (Eph 5:15-16).</p>", "13": "<p><span class=\"level\">shadow</span> <em>Return, O LORD! How long? Have pity on your servants!</em> The <em>how long</em> and <em>return</em> — the church's eschatological prayer: <em>Come, Lord Jesus!</em> (Rev 22:20). Christ taught this urgency: the parable of the persistent widow who cries <em>give me justice</em> (Luke 18:1-8) is the church's cry for the returning Lord. The <em>return</em> is the parousia of the Son.</p>", "14": "<p><span class=\"level\">revelation of God</span> <em>Satisfy us in the morning with your steadfast love, that we may rejoice and be glad all our days.</em> Morning satisfaction with steadfast love — the resurrection morning. Mary Magdalene at the empty tomb (John 20:1,16 — <em>she turned and said Rabboni!</em>) is the morning satisfaction that launches the church's rejoicing. The steadfast love (chesed) that satisfies is made flesh in Christ (John 1:14 — <em>full of grace and truth</em>).</p>", "15": "<p><span class=\"level\">shadow</span> <em>Make us glad for as many days as you have afflicted us, and for as many years as we have seen evil.</em> Gladness proportionate to affliction — the eschatological reversal. Paul: <em>for I consider that the sufferings of this present time are not worth comparing with the glory that is to be revealed to us</em> (Rom 8:18). The years of affliction give way to eternal joy; the proportion favors the believer infinitely.</p>", "16": "<p><span class=\"level\">shadow</span> <em>Let your work be shown to your servants, and your glorious power to their children.</em> God's work shown — the Incarnation is the supreme display of God's work and glory: <em>we have seen his glory, glory as of the only Son from the Father, full of grace and truth</em> (John 1:14). The Spirit continues showing this work to each generation's children (John 16:13-15 — <em>he will glorify me</em>).</p>", "17": "<p><span class=\"level\">shadow</span> <em>Let the favor of the Lord our God be upon us, and establish the work of our hands upon us; yes, establish the work of our hands!</em> The favor of the Lord — the Aaronic blessing fulfilled in Christ (Num 6:25; 2 Cor 4:6). The work of our hands established — the church's labor in Christ is not in vain: <em>be steadfast, immovable, always abounding in the work of the Lord, knowing that in the Lord your labor is not in vain</em> (1 Cor 15:58).</p>"}, "91": {"1": "<p><span class=\"level\">shadow</span> <em>He who dwells in the shelter of the Most High will abide in the shadow of the Almighty.</em> The shelter of the Most High — Christ is both the one who dwells in perfect shelter (his communion with the Father is absolute) and the shelter itself: <em>in him all the fullness of God was pleased to dwell</em> (Col 1:19). Those who are <em>in Christ</em> (Paul's phrase 164 times) abide in the same shadow that protected the Son.</p>", "2": "<p><span class=\"level\">shadow</span> <em>I will say to the LORD, My refuge and my fortress, my God, in whom I trust.</em> The confession of trust — Christ's own posture toward the Father throughout his ministry: <em>Father, into your hands I commit my spirit</em> (Luke 23:46). He modeled absolute refuge and trust in God at the moment of greatest vulnerability. The believer's confession of God as refuge is grounded in Christ's prior, perfect trust.</p>", "3": "<p><span class=\"level\">shadow</span> <em>For he will deliver you from the snare of the fowler and from the deadly pestilence.</em> Deliverance from the snare — the snare of death that Christ escaped through resurrection. Those who laid snares for him (Ps 35:7; John 11:53) failed to trap him permanently. The deadly pestilence that is sin and death he overcame (1 Cor 15:55-57) so that those in him share his deliverance.</p>", "4": "<p><span class=\"level\">shadow</span> <em>He will cover you with his pinions, and under his wings you will find refuge; his faithfulness is a shield and buckler.</em> The sheltering wings — Christ's own image for his longing over Jerusalem: <em>How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!</em> (Matt 23:37). The longing to shelter is the Incarnation motive; the cross is where the wings are spread widest.</p>", "5": "<p><span class=\"level\">shadow</span> <em>You will not fear the terror of the night, nor the arrow that flies by day,</em> Freedom from fear — the gift Christ gives: <em>Peace I leave with you; my peace I give to you. Not as the world gives do I give to you. Let not your hearts be troubled, neither let them be afraid</em> (John 14:27). The terror of the night and arrows of the day are the fears the resurrection makes manageable, since death itself — the greatest terror — is overcome.</p>", "6": "<p><span class=\"level\">shadow</span> <em>nor the pestilence that stalks in darkness, nor the destruction that wastes at noonday.</em> The pestilence and destruction — the background radiation of the fallen world. Christ walks through the valley of the shadow of death (Ps 23:4) without being consumed, and promises those in him the same passage. <em>I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live</em> (John 11:25).</p>", "7": "<p><span class=\"level\">shadow</span> <em>A thousand may fall at your side, ten thousand at your right hand, but it will not come near you.</em> The one who stands while others fall — Christ stands at the right hand of God (Acts 7:56) while all others fall under judgment. Those in him are kept: <em>who shall separate us from the love of Christ?</em> (Rom 8:35). Nothing that destroys others can ultimately destroy those sheltered in the risen Christ.</p>", "8": "<p><span class=\"level\">shadow</span> <em>You will only look with your eyes and see the recompense of the wicked.</em> Witnessing the recompense — the perspective of those vindicated at the last judgment. The risen Christ sees the recompense of those who opposed him; those in him share in this vindication. <em>The God of peace will soon crush Satan under your feet</em> (Rom 16:20) — the believer sees the enemy's defeat.</p>", "9": "<p><span class=\"level\">shadow</span> <em>Because you have made the LORD your dwelling place — the Most High, who is my refuge —</em> The Lord as dwelling place — John 15:4-5: <em>abide in me, and I in you.</em> Christ is the dwelling place; those who make him their refuge are sheltered. The mutual indwelling of Christ and believer (John 17:21-23) is the fulfillment of the shelter promised here — not an abstract God-refuge but union with the incarnate Son.</p>", "10": "<p><span class=\"level\">shadow</span> <em>no evil shall be allowed to befall you, no plague come near your tent.</em> The protection of the one who dwells in God — not a promise of physical immunity but of ultimate security. Christ's promise: <em>I give them eternal life, and they will never perish, and no one will snatch them out of my hand</em> (John 10:28). The plague that cannot touch the believer is the second death (Rev 20:6 — <em>over such the second death has no power</em>).</p>", "11": "<p><span class=\"level\">direct</span> <em>For he will command his angels concerning you to guard you in all your ways.</em> Satan quotes this verse directly to Jesus during the wilderness temptation (Matt 4:6; Luke 4:10-11), demanding that he throw himself from the temple pinnacle. Jesus refuses — not denying the promise but refusing to weaponize it against the Father's will. Christ is the one to whom this promise supremely applies; he does not presume upon it but trusts the Father's timing.</p>", "12": "<p><span class=\"level\">direct</span> <em>On their hands they will bear you up, lest you strike your foot against a stone.</em> Continued from v11 — Satan's second temptation citation (Matt 4:6; Luke 4:11). Christ responds: <em>you shall not put the Lord your God to the test</em> (Matt 4:7, citing Deut 6:16). The promise is real — angels do minister to Christ (Matt 4:11; Luke 22:43) — but never on Satan's terms. Christ trusts the Father to deploy the promise in his own way and time.</p>", "13": "<p><span class=\"level\">shadow</span> <em>You will tread on the lion and the adder; the young lion and the serpent you will trample underfoot.</em> Christ trampling the ancient serpent — Gen 3:15 (enmity between the woman's seed and the serpent). <em>The God of peace will soon crush Satan under your feet</em> (Rom 16:20). Christ gave the seventy-two authority: <em>I have given you authority to tread on serpents and scorpions and over all the power of the enemy</em> (Luke 10:19). The trampling is accomplished through the cross (Col 2:15).</p>", "14": "<p><span class=\"level\">shadow</span> <em>Because he holds fast to me in love, I will deliver him; I will protect him, because he knows my name.</em> God speaking: the one who holds fast in love is delivered. Christ holds fast to the Father in perfect love through every trial — Gethsemane, the cross, the tomb — and is delivered through resurrection. Heb 5:7: <em>he was heard because of his reverence.</em> The resurrection is the divine <em>I will deliver him.</em></p>", "15": "<p><span class=\"level\">shadow</span> <em>When he calls to me, I will answer him; I will be with him in trouble; I will rescue him and honor him.</em> God promises to answer, be present, rescue, and honor. All four are fulfilled in Christ: the Father answers Gethsemane's cry (Heb 5:7), is present through the Spirit in the Passion (Luke 23:46), rescues through resurrection (Acts 2:24), and honors through exaltation: <em>God has highly exalted him and bestowed on him the name above every name</em> (Phil 2:9).</p>", "16": "<p><span class=\"level\">shadow</span> <em>With long life I will satisfy him and show him my salvation.</em> Long life — the resurrection life that has no end: <em>I am the living one. I died, and behold I am alive forevermore</em> (Rev 1:18). Christ is satisfied with the outcome of his suffering: <em>he shall see his offspring; he shall prolong his days; the will of the LORD shall prosper in his hand</em> (Isa 53:10). The salvation God shows him is the salvation he himself is (Luke 2:30 — <em>my eyes have seen your salvation</em>).</p>"}, "92": {"1": "<p><span class=\"level\">theme</span> <em>It is good to give thanks to the LORD, to sing praises to your name, O Most High;</em> The Sabbath psalm's opening — Christ is Lord of the Sabbath (Matt 12:8), and the rest he provides is the true Sabbath (Heb 4:9-11). Giving thanks through Christ: <em>through him then let us continually offer up a sacrifice of praise to God</em> (Heb 13:15). The name Most High is the name Jesus bears (Mark 5:7 — <em>Son of the Most High God</em>).</p>", "2": "<p><span class=\"level\">theme</span> <em>to declare your steadfast love in the morning, and your faithfulness by night,</em> Morning and night praise — the ceaseless doxology. Christ models this: night prayers on the mountain (Luke 6:12), morning rising to pray (Mark 1:35). His steadfast love (hesed) declared is the gospel itself: <em>God shows his love for us in that while we were still sinners, Christ died for us</em> (Rom 5:8).</p>", "3": "<p><span class=\"level\">theme</span> <em>to the music of the lute and the harp, to the melody of the lyre.</em> Musical praise — the worship of the new covenant community gathered around Christ. Eph 5:19: <em>addressing one another in psalms and hymns and spiritual songs, singing and making melody to the Lord with your heart.</em> The Spirit-filled church takes up the instruments of the Psalter and directs them at the risen Christ.</p>", "4": "<p><span class=\"level\">theme</span> <em>For you, O LORD, have made me glad by your work; at the works of your hands I sing for joy.</em> Gladness in God's works — the works of Christ producing joy: <em>these things I have spoken to you, that my joy may be in you, and that your joy may be full</em> (John 15:11). The disciples' gladness when they see the risen Lord (John 20:20) is the paradigm — the works of the Lord's hands (the resurrection) are the source of inexpressible joy.</p>", "5": "<p><span class=\"level\">revelation of God</span> <em>How great are your works, O LORD! Your thoughts are very deep!</em> The greatness of God's works and the depth of his thoughts — Paul erupts in the same doxology after explaining the mystery of Christ and the church: <em>Oh, the depth of the riches and wisdom and knowledge of God! How unsearchable are his judgments and how inscrutable his ways!</em> (Rom 11:33). The deep thoughts of God are the wisdom that is Christ himself (1 Cor 1:24).</p>", "6": "<p><span class=\"level\">theme</span> <em>The stupid man cannot know; the fool cannot understand this:</em> The fool who cannot understand — the natural man who cannot receive the things of the Spirit of God (1 Cor 2:14). The wisdom of the cross is foolishness to those who are perishing (1 Cor 1:18) — the depth of God's works in Christ is hidden from the foolish and revealed to babes (Matt 11:25).</p>", "7": "<p><span class=\"level\">theme</span> <em>that though the wicked sprout like grass and all evildoers flourish, they are doomed to destruction forever,</em> The flourishing wicked doomed to destruction — the eschatological reversal. Christ's parable of wheat and tares (Matt 13:24-30): the tares flourish alongside the wheat until the harvest, when they are gathered for burning. The apparent prosperity of the wicked is temporary; the doom is certain and forever.</p>", "8": "<p><span class=\"level\">revelation of God</span> <em>but you, O LORD, are on high forever.</em> The eternal height of God — fulfilled in the Ascension of Christ: <em>he ascended far above all the heavens, that he might fill all things</em> (Eph 4:10). The one who is on high forever is the same Christ who descended to earth's depths and rose to fill all things. The eternal highness is the highness of the crucified and risen Lord.</p>", "9": "<p><span class=\"level\">shadow</span> <em>For behold, your enemies, O LORD, for behold, your enemies shall perish; all evildoers shall be scattered.</em> The perishing of God's enemies — fulfilled ultimately at the parousia. <em>He must reign until he has put all his enemies under his feet. The last enemy to be destroyed is death</em> (1 Cor 15:25-26). The scattering of evildoers begins at the cross (the powers disarmed, Col 2:15) and completes at the last day.</p>", "10": "<p><span class=\"level\">shadow</span> <em>But you have exalted my horn like that of the wild ox; you have poured over me fresh oil.</em> Exalted horn and fresh oil — the anointing of the Messiah. Christ = Anointed One; the Spirit descends on him like oil at his baptism (Matt 3:16; Isa 61:1 — <em>the Spirit of the Lord is upon me, because he has anointed me</em>). God exalts his horn through the resurrection and enthronement (Phil 2:9-11).</p>", "11": "<p><span class=\"level\">shadow</span> <em>My eyes have seen the downfall of my enemies; my ears have heard the doom of my evil assailants.</em> Seeing the downfall of enemies — the vindicated righteous one's perspective. Christ sees the defeat of his enemies from his enthronement at the Father's right hand: <em>the Lord said to my Lord, Sit at my right hand, until I make your enemies your footstool</em> (Ps 110:1; Matt 22:44). He waits from the position of victory already secured.</p>", "12": "<p><span class=\"level\">shadow</span> <em>The righteous flourish like the palm tree and grow like a cedar in Lebanon.</em> The righteous flourishing — the fruitful branches abiding in Christ: <em>I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit</em> (John 15:5). The palm and cedar are the imagery of permanence and dignity; those in Christ grow with the stability of deep-rooted trees.</p>", "13": "<p><span class=\"level\">shadow</span> <em>They are planted in the house of the LORD; they flourish in the courts of our God.</em> Planted in God's house — <em>rooted and grounded in love</em> (Eph 3:17); planted in Christ who is the true temple (John 2:21). The courts of God are now the gathering of the church around the risen Christ, in whom the fullness of the Godhead dwells bodily (Col 2:9).</p>", "14": "<p><span class=\"level\">shadow</span> <em>They still bear fruit in old age; they are ever full of sap and green,</em> Fruitful in old age — the eternal fruitfulness of those in Christ who drink from the living water: <em>the water that I will give him will become in him a spring of water welling up to eternal life</em> (John 4:14). The green, sap-full tree is the believer permanently rooted in Christ, bearing fruit that remains (John 15:16).</p>", "15": "<p><span class=\"level\">shadow</span> <em>to declare that the LORD is upright; he is my rock, and there is no unrighteousness in him.</em> The upright rock with no unrighteousness — Christ: <em>in him there is no sin</em> (1 John 3:5); <em>no deceit was found in his mouth</em> (1 Pet 2:22; Isa 53:9). The rock is Christ (1 Cor 10:4). The declaration of God's uprightness is the declaration of Christ's righteousness — the foundation on which the justified sinner stands.</p>"}, "93": {"1": "<p><span class=\"level\">direct</span> <em>The LORD reigns; he is robed in majesty; the LORD is robed; he has put on strength as his belt. Yes, the world is established; it shall never be moved.</em> The LORD who reigns is Christ enthroned: <em>all authority in heaven and on earth has been given to me</em> (Matt 28:18). Revelation applies this throne imagery to Christ throughout (Rev 4-5; 19:6 — <em>the Lord our God the Almighty reigns</em>). His majesty is the Ascension glory; his belt of strength is the power of the resurrection.</p>", "2": "<p><span class=\"level\">direct</span> <em>Your throne is established from of old; you are from everlasting.</em> The eternal throne — Hebrews 1:8 applies Ps 45:6 to Christ: <em>Your throne, O God, is forever and ever.</em> The one from everlasting is the Christ who pre-exists all creation (John 1:1 — <em>in the beginning was the Word</em>; Col 1:17 — <em>he is before all things</em>). The ancient throne is the throne of the Son of God.</p>", "3": "<p><span class=\"level\">shadow</span> <em>The floods have lifted up, O LORD, the floods have lifted up their voice; the floods lift up their roaring.</em> Roaring floods — the chaos waters that threaten. Christ commands the chaos: <em>Peace! Be still!</em> (Mark 4:39) — the disciples ask, <em>Who then is this, that even the wind and the sea obey him?</em> The one mightier than the roaring floods is the LORD of Ps 93, present in the boat.</p>", "4": "<p><span class=\"level\">shadow</span> <em>Mightier than the thunders of many waters, mightier than the waves of the sea, the LORD on high is mighty!</em> Mightier than the waves — the LORD who stills the storm is Christ. His voice of authority over nature (Matt 8:26; Mark 4:39; Luke 8:24) demonstrates his identity as the creator-God who is mightier than every force of chaos. The voice like many waters in Rev 1:15 is the voice of the risen Christ.</p>", "5": "<p><span class=\"level\">shadow</span> <em>Your decrees are very trustworthy; holiness befits your house, O LORD, forevermore.</em> Holiness befitting God's house — Christ cleanses the temple as an act of divine holiness (John 2:13-17). But he is himself the new house where holiness dwells: <em>for in him the whole fullness of deity dwells bodily</em> (Col 2:9). The trustworthy decrees are the words of Christ: <em>heaven and earth will pass away, but my words will not pass away</em> (Matt 24:35).</p>"}, "94": {"1": "<p><span class=\"level\">shadow</span> <em>O LORD, God of vengeance, O God of vengeance, shine forth!</em> God of vengeance shining forth — the parousia of Christ: <em>when the Lord Jesus is revealed from heaven with his mighty angels in flaming fire, inflicting vengeance on those who do not know God</em> (2 Thess 1:7-8). The shining forth is the glory of Christ's return; the vengeance is the just judgment committed to the Son (John 5:22).</p>", "2": "<p><span class=\"level\">shadow</span> <em>Rise up, O judge of the earth; repay to the proud what they deserve!</em> The Judge of the earth rising — Christ the appointed judge: <em>he has fixed a day on which he will judge the world in righteousness by a man whom he has appointed; and of this he has given assurance to all by raising him from the dead</em> (Acts 17:31). The resurrection is the credential of the Judge; the proud are repaid at the last day.</p>", "3": "<p><span class=\"level\">shadow</span> <em>O LORD, how long shall the wicked, how long shall the wicked exult?</em> The <em>how long</em> of the martyrs — <em>how long before you will judge and avenge our blood on those who dwell on the earth?</em> (Rev 6:10). Christ's answer is the promise of vindication at the set time. The wicked exulting at the cross seemed victorious; the resurrection was the first answer to <em>how long</em>; the parousia is the final one.</p>", "4": "<p><span class=\"level\">theme</span> <em>They pour out their arrogant words; all the evildoers boast.</em> Arrogant words against God — the speech of those who mocked Christ on the cross (Matt 27:39-44) and those who blaspheme throughout history. <em>Whoever speaks against the Son of Man will be forgiven, but whoever speaks against the Holy Spirit will not be forgiven</em> (Matt 12:32). The boasting of evildoers faces the silencing judgment of the one who speaks with divine authority.</p>", "5": "<p><span class=\"level\">shadow</span> <em>They crush your people, O LORD, and afflict your heritage.</em> The crushing of God's people — the suffering of believers patterned on Christ's own suffering: <em>a servant is not greater than his master. If they persecuted me, they will also persecute you</em> (John 15:20). Christ identifies with the crushed: <em>as you did it to one of the least of these my brothers, you did it to me</em> (Matt 25:40).</p>", "6": "<p><span class=\"level\">shadow</span> <em>They kill the widow and the sojourner, and murder the fatherless;</em> The murder of the vulnerable — the oppression Christ came to address (Luke 4:18 — good news to the poor; release to the captives). His identification with the least (Matt 25:40) means every murdered widow and orphan is an offense against Christ himself. The Judge who rises to defend them is the one who cared for them in his earthly ministry.</p>", "7": "<p><span class=\"level\">shadow</span> <em>and they say, The LORD does not see; the God of Jacob does not perceive.</em> <em>God does not see</em> — the arrogance of those who sinned in the dark, thinking God absent. Christ exposes this: <em>nothing is hidden that will not be revealed, or secret that will not be known</em> (Matt 10:26). Before him all things are naked and exposed (Heb 4:13); his eyes like flames of fire see everything (Rev 1:14).</p>", "8": "<p><span class=\"level\">theme</span> <em>Understand, O dullest of the people! Fools, when will you be wise?</em> The call to wisdom — Christ calls the foolish to wisdom: <em>come to me, all who labor and are heavy laden, and I will give you rest... learn from me</em> (Matt 11:28-29). The wisdom that the fool lacks is the wisdom from above (James 3:17); it is found in Christ who became to us wisdom from God (1 Cor 1:30).</p>", "9": "<p><span class=\"level\">shadow</span> <em>He who planted the ear, does he not hear? He who formed the eye, does he not see?</em> The Creator who hears and sees — Christ demonstrates this in John 9: he sees the blind man (John 9:1), heals his eyes (John 9:6-7), and then announces: <em>For judgment I came into this world, that those who do not see may see, and those who see may become blind</em> (John 9:39). The one who formed the eye comes to restore sight.</p>", "10": "<p><span class=\"level\">shadow</span> <em>He who disciplines nations, does he not rebuke? He who teaches man knowledge —</em> God who disciplines nations and teaches knowledge — Christ rebukes and teaches with divine authority (Matt 7:29 — <em>he taught them as one who had authority, and not as their scribes</em>). His rebukes to the Pharisees (Matt 23) and his teaching of the nations (Matt 28:20 — <em>teaching them to observe all that I have commanded</em>) fulfill this verse.</p>", "11": "<p><span class=\"level\">direct</span> <em>the LORD — knows the thoughts of man, that they are but a breath.</em> 1 Corinthians 3:20 quotes this verse: <em>The Lord knows the thoughts of the wise, that they are futile.</em> Paul uses it to demolish human wisdom-boasting and ground all confidence in Christ crucified. The God who knows human thoughts as futile — including the thoughts of those who crucified his Son — is the one who raises the foolish things of the world to shame the wise.</p>", "12": "<p><span class=\"level\">shadow</span> <em>Blessed is the man whom you discipline, O LORD, and whom you teach out of your law,</em> The discipline of the LORD — applied to believers in Hebrews 12:5-11 (citing Prov 3:11-12): <em>the Lord disciplines the one he loves.</em> Christ himself learned obedience through what he suffered (Heb 5:8) — the ultimate example of divine discipline producing the fruit of righteousness. His disciples are discipled (the same root) by following him through suffering.</p>", "13": "<p><span class=\"level\">shadow</span> <em>to give him rest from days of trouble, until a pit is dug for the wicked.</em> Rest from trouble — the rest Christ provides: <em>Come to me, all who labor and are heavy laden, and I will give you rest</em> (Matt 11:28). The ultimate rest is the sabbath rest that remains for the people of God (Heb 4:9-11), entered through faith in Christ. The pit dug for the wicked is the eschatological judgment of those who rejected him.</p>", "14": "<p><span class=\"level\">shadow</span> <em>For the LORD will not forsake his people; he will not abandon his heritage.</em> The LORD will not forsake — Christ's great promise: <em>I am with you always, to the end of the age</em> (Matt 28:20). Paul's certainty: <em>I am sure that neither death nor life... will be able to separate us from the love of God in Christ Jesus our Lord</em> (Rom 8:38-39). The never-forsaking God is the Christ who went through abandonment on the cross so he might be the unforsaking Shepherd forever.</p>", "15": "<p><span class=\"level\">shadow</span> <em>for justice will return to the righteous, and all the upright in heart will follow it.</em> Justice returning to the righteous — the eschatological reversal. Christ is the righteous one (Acts 3:14 — <em>you denied the Holy and Righteous One</em>) to whom justice returns at the resurrection. All who are upright in heart — those clothed in his righteousness (Phil 3:9) — follow in his vindication.</p>", "16": "<p><span class=\"level\">shadow</span> <em>Who rises up for me against the wicked? Who stands up for me against evildoers?</em> Who rises up? — Christ rises up for the oppressed. Acts 7:55-56: Stephen sees <em>Jesus standing at the right hand of God</em> — he rises to welcome his martyr. The one who rose from the dead rises for those who are persecuted. He stands as advocate (1 John 2:1 — <em>we have an advocate with the Father, Jesus Christ the righteous</em>).</p>", "17": "<p><span class=\"level\">shadow</span> <em>If the LORD had not been my help, my soul would soon have lived in the land of silence.</em> The LORD as help — Heb 13:6 applies a similar promise directly: <em>I will never leave you nor forsake you</em>, leading to the declaration <em>The Lord is my helper; I will not fear.</em> The land of silence is death — from which Christ rescues those who trust him. He himself passed through the land of silence (the tomb) and came out, ensuring none of his own stay there.</p>", "18": "<p><span class=\"level\">shadow</span> <em>When I thought, My foot slips, your steadfast love, O LORD, held me up.</em> Steadfast love holding up the slipping foot — the preserving grace of Christ. <em>Now to him who is able to keep you from stumbling and to present you blameless before the presence of his glory with great joy</em> (Jude 24). The Shepherd who prays for Peter (Luke 22:32 — <em>I have prayed for you that your faith may not fail</em>) holds up the slipping foot.</p>", "19": "<p><span class=\"level\">shadow</span> <em>When the cares of my heart are many, your consolations cheer my soul.</em> Divine consolation — the Spirit as Comforter (John 14:16-17 — <em>I will ask the Father, and he will give you another Helper</em>). The consolations that cheer the soul are the consolations of Christ given through the Spirit: <em>if there is any comfort in Christ... any participation in the Spirit... complete my joy</em> (Phil 2:1-2).</p>", "20": "<p><span class=\"level\">shadow</span> <em>Can wicked rulers be allied with you, who frame injustice by statute?</em> Unjust rulers framing injustice by statute — the Roman and Jewish authorities who condemned Christ through legal process while he was innocent. Pilate found no fault (Luke 23:4), yet sentenced him; the Sanhedrin condemned him on charges of blasphemy against their own manipulated law. Injustice by statute is the mechanism of the Passion.</p>", "21": "<p><span class=\"level\">shadow</span> <em>They band together against the life of the righteous and condemn the innocent to death.</em> Banding against the righteous to condemn the innocent — Acts 4:27: <em>for truly in this city there were gathered together against your holy servant Jesus, whom you anointed, both Herod and Pontius Pilate, along with the Gentiles and the peoples of Israel.</em> The banding together against Christ is the supreme fulfillment of this verse.</p>", "22": "<p><span class=\"level\">shadow</span> <em>But the LORD has become my stronghold, and my God the rock of my refuge.</em> The LORD as stronghold and rock — Christ the rock of refuge (1 Cor 10:4). The vindicated righteous one finds refuge in the God who raised him; those condemned by the same injustice find in Christ their stronghold. The rock that was struck to bring forth water (Exod 17) is the same rock that is the refuge from every storm.</p>", "23": "<p><span class=\"level\">shadow</span> <em>He will bring back on them their iniquity and wipe them out for their evil; the LORD our God will wipe them out.</em> Iniquity brought back — the principle of divine justice at the last judgment. Christ will judge: <em>Behold, I am coming soon, bringing my recompense with me, to repay each one for what he has done</em> (Rev 22:12). The wiping out of evildoers is the work of the one who first wiped out the sin of those who trust him (Col 2:14 — <em>canceling the record of debt</em>).</p>"}, "95": {"1": "<p><span class=\"level\">shadow</span> <em>Oh come, let us sing to the LORD; let us make a joyful noise to the rock of our salvation!</em> The rock of our salvation — Christ: <em>the Rock was Christ</em> (1 Cor 10:4); <em>he is my rock and my salvation</em> (Ps 62:2). The joyful noise is the church's praise directed at the risen Lord (Heb 13:15 — <em>through him then let us continually offer up a sacrifice of praise</em>). The singing to the LORD is the singing of the church to Christ.</p>", "2": "<p><span class=\"level\">theme</span> <em>Let us come into his presence with thanksgiving; let us make a joyful noise to him with songs of praise!</em> Coming into his presence with thanksgiving — the church's gathered worship. Eph 5:19-20: <em>singing and making melody to the Lord with your heart, giving thanks always and for everything to God the Father in the name of our Lord Jesus Christ.</em> Presence, thanksgiving, and song are constitutive elements of Christ-centered worship.</p>", "3": "<p><span class=\"level\">direct</span> <em>For the LORD is a great God, and a great King above all gods.</em> The great King above all gods — Christ: <em>King of kings and Lord of lords</em> (Rev 17:14; 19:16). Every earthly power, every spiritual principality is beneath the authority of the risen Christ who is given all authority in heaven and on earth (Matt 28:18). The great God is the one who became flesh and dwelt among us.</p>", "4": "<p><span class=\"level\">revelation of God</span> <em>In his hand are the depths of the earth; the heights of the mountains are his also.</em> Christ holds the depths and heights — <em>he ascended far above all the heavens, that he might fill all things</em> (Eph 4:10). The one who descended to the depths of the earth (death) and ascended to the heights holds all creation in his hand. <em>In him all things hold together</em> (Col 1:17).</p>", "5": "<p><span class=\"level\">revelation of God</span> <em>The sea is his, for he made it, and his hands formed the dry land.</em> The Creator of sea and land — the same hands that formed dry land stilled the storm on Galilee (Mark 4:39). Christ as creator (John 1:3; Col 1:16 — <em>all things were created through him and for him</em>) is the LORD of Ps 95 who owns the sea and formed the land. His command over creation reveals his identity.</p>", "6": "<p><span class=\"level\">shadow</span> <em>Oh come, let us worship and bow down; let us kneel before the LORD, our Maker!</em> Bowing and kneeling before the LORD — the posture of Phil 2:10: <em>at the name of Jesus every knee should bow, in heaven and on earth and under the earth.</em> The worship called for in Ps 95:6 is the worship every creature ultimately gives to Christ — voluntarily now in the church, finally and universally at the parousia.</p>", "7": "<p><span class=\"level\">direct</span> <em>For he is our God, and we are the people of his pasture, and the sheep of his hand. Today, if you hear his voice,</em> <em>Today, if you hear his voice</em> — Heb 3:7-8 quotes this verse as a direct word of the Holy Spirit: <em>Therefore, as the Holy Spirit says, Today, if you hear his voice, do not harden your hearts.</em> Hebrews applies the warning to the church hearing Christ's voice in the present moment — the <em>today</em> of Christ's call is the present moment of every hearer.</p>", "8": "<p><span class=\"level\">direct</span> <em>do not harden your hearts, as at Meribah, as on the day at Massah in the wilderness,</em> Hebrews 3:8 continues the citation: <em>do not harden your hearts as in the rebellion, on the day of testing in the wilderness.</em> The wilderness hardening becomes the anti-pattern for those who have heard the gospel of Christ. The testing at Meribah (water from the rock = Christ, 1 Cor 10:4) is now the testing of whether one trusts Christ in the present.</p>", "9": "<p><span class=\"level\">direct</span> <em>when your fathers put me to the test and put me to the proof, though they had seen my work.</em> Hebrews 3:9 continues: the Israelites who saw God's work and still tested him are the warning to those who have seen Christ's works (John 12:37) and still refuse to believe. The testing of God in the wilderness is the same as testing Christ (1 Cor 10:9 — <em>we must not put Christ to the test, as some of them did</em>).</p>", "10": "<p><span class=\"level\">direct</span> <em>For forty years I loathed that generation and said, They are a people who go astray in their heart, and they have not known my ways.</em> Hebrews 3:10 quotes this exactly: <em>I was provoked with that generation, and said, They always go astray in their heart; they have not known my ways.</em> The forty years of wandering becomes the image for a generation that refuses Christ — going astray in the heart is the refusal to enter the rest that Christ provides.</p>", "11": "<p><span class=\"level\">direct</span> <em>Therefore I swore in my wrath, They shall not enter my rest.</em> Hebrews 3:11 cites this directly, then expands it throughout chapters 3-4: the rest the wilderness generation failed to enter is the Sabbath rest that remains for the people of God (Heb 4:9). <em>Let us therefore strive to enter that rest</em> (Heb 4:11) — the rest entered through faith in Christ, who is himself the fulfillment of the Sabbath (Matt 11:28-29 — <em>I will give you rest</em>).</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
